/**
 * Lightweight AFINN-165 sentiment analyzer (self-contained, no dependencies)
 * Subset of the AFINN-165 word list, optimized for lyric analysis.
 */
(function (global) {
  const AFINN = {
    // Positive
    love: 3, loved: 3, loving: 3, beautiful: 3, beauty: 3, amazing: 4, wonderful: 4,
    great: 3, good: 2, happy: 3, happiness: 3, joy: 3, joyful: 3,
    fantastic: 4, excellent: 4, perfect: 3, awesome: 4, brilliant: 3,
    incredible: 4, magnificent: 4, glorious: 3, radiant: 3, bliss: 4,
    euphoric: 5, ecstasy: 5, elated: 4, excited: 3, thrilled: 4,
    grateful: 3, thankful: 2, blessed: 3, hope: 2, hopeful: 2,
    dream: 2, dreams: 2, shine: 2, shining: 2, light: 2, bright: 2,
    smile: 2, smiling: 2, laugh: 2, laughter: 3, free: 2, freedom: 3,
    alive: 2, rise: 2, rising: 2, soar: 3, fly: 2, dance: 2, dancing: 2,
    sing: 2, singing: 2, celebrate: 3, celebration: 3, paradise: 4,
    heaven: 4, magic: 3, miracle: 4, strong: 2, strength: 2, power: 2,
    overcome: 2, victory: 3, win: 2, winning: 2, success: 3, together: 2,
    forever: 2, eternity: 2, warm: 2, warmth: 2, sweet: 2, gentle: 2,
    peace: 3, peaceful: 3, serene: 3, calm: 2, safe: 2, comfort: 2,
    trust: 2, faith: 2, believe: 2,
    // Negative
    hate: -3, hated: -3, awful: -3, terrible: -3, horrible: -3,
    bad: -2, sad: -2, sadness: -3, unhappy: -2, depressed: -3, depression: -3,
    pain: -2, painful: -3, hurt: -2, hurting: -2, cry: -2, crying: -2,
    tears: -2, lonely: -3, alone: -2, lost: -2, broken: -3, shattered: -3,
    empty: -3, hollow: -2, numb: -2, dark: -2, darkness: -3, shadow: -2,
    fear: -2, afraid: -2, scared: -2, terror: -4, dread: -3, horror: -4,
    anger: -3, angry: -3, rage: -4, fury: -4, violent: -4,
    violence: -4, destroy: -3, destroyed: -3, dead: -3, death: -3, die: -3,
    dying: -3, kill: -4, killing: -4, murder: -4, blood: -3, war: -3,
    battle: -2, fight: -2, fighting: -2, scream: -2, screaming: -2,
    burn: -2, burning: -2, fire: -1, crash: -3, fail: -2, failure: -2,
    despair: -4, hopeless: -3, misery: -4, agony: -4, suffer: -3,
    suffering: -3, grief: -3, sorrow: -3, regret: -2, shame: -2,
    guilty: -2, worthless: -4, useless: -2, ugly: -3, wrong: -2,
    betrayal: -4, betrayed: -4, lied: -3, lie: -2, lies: -2,
    cold: -1, distance: -1, fading: -2, gone: -2, leaving: -2,
    miss: -2, missing: -2, forget: -2, forgetting: -2, abandoned: -3,
  };

  // Intensity multipliers — stored separately to avoid mixing with scored words
  const INTENSIFIERS = {
    very: 1.5, so: 1.2, really: 1.3, absolutely: 1.5, completely: 1.4,
    totally: 1.3, extremely: 1.6, incredibly: 1.5, deeply: 1.4,
  };


  const NEGATIONS = new Set(['not', 'no', "n't", 'never', 'neither', 'without', 'hardly', 'barely']);

  function analyze(text) {
    if (!text || !text.trim()) return { score: 0, comparative: 0, tokens: [] };

    const tokens = text.toLowerCase().replace(/[^\w\s']/g, '').split(/\s+/);
    let score = 0;
    let wordCount = 0;
    let lastNegationIdx = -1;

    for (let i = 0; i < tokens.length; i++) {
      const word = tokens[i].replace(/'/g, '');
      if (!word) continue;

      if (NEGATIONS.has(word)) { lastNegationIdx = i; continue; }

      const val = AFINN[word];
      if (val !== undefined) {
        // Negation is only valid if it appeared recently (within 3 words)
        const modifier = (lastNegationIdx !== -1 && (i - lastNegationIdx <= 3)) ? -1 : 1;
        
        let intensityMod = 1;
        // Check immediate previous word for intensifier
        const prevWord = i > 0 ? tokens[i - 1].replace(/'/g, '') : '';
        if (INTENSIFIERS[prevWord]) {
          intensityMod = INTENSIFIERS[prevWord];
        } 
        // If the immediate previous word was a negation, check the word before that for intensifier (e.g. "really not good")
        else if (i > 1 && lastNegationIdx === i - 1) {
          const prevPrevWord = tokens[i - 2].replace(/'/g, '');
          if (INTENSIFIERS[prevPrevWord]) {
            intensityMod = INTENSIFIERS[prevPrevWord];
          }
        }

        score += val * modifier * intensityMod;
        wordCount++;
        lastNegationIdx = -1; // consume the negation
      }
    }

    const comparative = wordCount > 0 ? score / wordCount : 0;
    return { score, comparative, tokens, wordCount };
  }

  const Sentiment = { analyze, AFINN };

  if (typeof module !== 'undefined' && module.exports) {
    module.exports = Sentiment;
  } else {
    global.Sentiment = Sentiment;
  }
})(typeof window !== 'undefined' ? window : this);
